mapper.select:
SELECT t.title,t.create_time, ifnull(t.update_time, t.create_time) as update_time,t.create_user,t.id,t.b_id, t1.real_name create_user_name, t2.sw_id FROM kb_basic_history t LEFT OUTER JOIN castle_sys_user t1 ON t.create_user = t1.id LEFT OUTER JOIN kb_category t2 ON t.category_id = t2.id WHERE t.is_deleted = 2
and t.b_id =#{kbBasicHistoryEntity.bId}
and t.create_time <= #{kbBasicHistoryEntity.createTime}
union all SELECT t.title,t.create_time, ifnull(t.update_time, t.create_time) as update_time,t.create_user,t.id, t.id as b_id, t1.real_name create_user_name, t2.sw_id FROM kb_basic t LEFT OUTER JOIN castle_sys_user t1 ON t.create_user = t1.id LEFT OUTER JOIN kb_category t2 ON t.category_id = t2.id WHERE t.is_deleted = 2 and t.id =#{kbBasicHistoryEntity.bId}
order by create_time desc
limit #{map.offset},#{map.rows}

select count(1) from ( SELECT t.title,t.create_time,t.create_user,t.id, t1.real_name create_user_name, t2.sw_id FROM kb_basic_history t LEFT OUTER JOIN castle_sys_user t1 ON t.create_user = t1.id LEFT OUTER JOIN kb_category t2 ON t.category_id = t2.id WHERE t.is_deleted = 2
and t.b_id =#{kbBasicHistoryEntity.bId}
and t.create_time <= #{kbBasicHistoryEntity.createTime}
union all SELECT t.title,t.create_time,t.create_user,t.id, t1.real_name create_user_name, t2.sw_id FROM kb_basic t LEFT OUTER JOIN castle_sys_user t1 ON t.create_user = t1.id LEFT OUTER JOIN kb_category t2 ON t.category_id = t2.id WHERE t.is_deleted = 2 and t.id =#{kbBasicHistoryEntity.bId} ) t
